import{_ as i,c as e,o as a,aj as t}from"./chunks/framework.guNMSiFm.js";const c=JSON.parse('{"title":"Troubleshooting Deployment Issues","description":"","frontmatter":{},"headers":[],"relativePath":"help/deployment-issues.md","filePath":"help/deployment-issues.md","lastUpdated":1777621302000}'),n={name:"help/deployment-issues.md"};function l(h,s,r,o,p,d){return a(),e("div",null,[...s[0]||(s[0]=[t(`<h1 id="troubleshooting-deployment-issues" tabindex="-1">Troubleshooting Deployment Issues <a class="header-anchor" href="#troubleshooting-deployment-issues" aria-label="Permalink to &quot;Troubleshooting Deployment Issues&quot;">​</a></h1><p>This section offers troubleshooting tips for issues with Iroha 2 and Iroha 3 deployment. If the issue you are experiencing is not described here, contact us via <a href="https://t.me/hyperledgeriroha" target="_blank" rel="noreferrer">Telegram</a>.</p><h2 id="start-with-generated-artifacts" tabindex="-1">Start with generated artifacts <a class="header-anchor" href="#start-with-generated-artifacts" aria-label="Permalink to &quot;Start with generated artifacts&quot;">​</a></h2><p>For local and test deployments, prefer artifacts generated by Kagami instead of hand-written peer files:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cargo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --bin</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> kagami</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> localnet</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --build-line</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> iroha3</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --peers</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 4</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --out-dir</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./localnet</span></span></code></pre></div><p>The generated directory contains peer configs, genesis material, start scripts, and a README for the selected build line. Use <code>--build-line iroha2</code> only when the deployment intentionally targets the Iroha 2 profile.</p><h2 id="peer-does-not-start" tabindex="-1">Peer does not start <a class="header-anchor" href="#peer-does-not-start" aria-label="Permalink to &quot;Peer does not start&quot;">​</a></h2><p>Check these items first:</p><ul><li><code>irohad --config &lt;path&gt;</code> points at the peer&#39;s own TOML file.</li><li><code>public_key</code> and <code>private_key</code> in the peer config belong to the same key pair.</li><li><code>genesis.public_key</code> matches the key used to sign the genesis transaction.</li><li>validator peer identities use BLS-Normal keys, and <code>trusted_peers_pop</code> contains proof-of-possession entries for the local key and trusted peers.</li><li>ports for Torii and P2P are not already bound by another process.</li><li>the Kura store directory belongs to the same chain and was not copied from a different network profile.</li></ul><p>Use config tracing when the daemon reads more than one TOML layer:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cargo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --bin</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> irohad</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --config</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./config.toml</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --trace-config</span></span></code></pre></div><h2 id="docker-and-compose" tabindex="-1">Docker and Compose <a class="header-anchor" href="#docker-and-compose" aria-label="Permalink to &quot;Docker and Compose&quot;">​</a></h2><p>Generate Compose from the current Kagami localnet output so the command-line arguments and config files match the checked-out code:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cargo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --bin</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> kagami</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> localnet</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --build-line</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> iroha3</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --peers</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 4</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --out-dir</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./localnet</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cargo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --bin</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> kagami</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> docker</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --peers</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 4</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --config-dir</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./localnet</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --image</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> hyperledger/iroha:dev</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --out-file</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./localnet/docker-compose.yml</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --force</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> compose</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -f</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./localnet/docker-compose.yml</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> up</span></span></code></pre></div><p>If a compose deployment starts and then stalls, inspect the daemon logs for:</p><ul><li>mismatched <code>chain</code></li><li>one peer using a different genesis transaction or manifest</li><li>advertised P2P addresses that only work inside the container network</li><li>local volume reuse after regenerating genesis</li></ul><p>When testing a fresh genesis, remove the old Kura volumes before restarting the stack. Keeping old block storage with a new genesis will make replay fail.</p><h2 id="kubernetes" tabindex="-1">Kubernetes <a class="header-anchor" href="#kubernetes" aria-label="Permalink to &quot;Kubernetes&quot;">​</a></h2><p>For Kubernetes, treat each validator as stateful infrastructure:</p><ul><li>give each peer a stable identity key and stable persistent volume</li><li>expose P2P addresses that other peers can resolve from inside the cluster</li><li>mount config and genesis files as immutable config for a rollout</li><li>roll out all genesis or topology changes deliberately, not as an automatic config-map refresh</li></ul><p>If a pod restarts repeatedly, compare the rendered config in the pod with the expected <a href="/iroha-2-docs/reference/peer-config/#template"><code>peer.template.toml</code></a> and check whether the peer is replaying old Kura data.</p><h2 id="sora-profile" tabindex="-1">Sora profile <a class="header-anchor" href="#sora-profile" aria-label="Permalink to &quot;Sora profile&quot;">​</a></h2><p>Iroha 3 deployments that use Nexus, SoraFS, or multi-lane flows should start the daemon with the Sora profile enabled:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cargo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --bin</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> irohad</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --config</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./config.toml</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --sora</span></span></code></pre></div><p>or:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">IROHA_SORA_PROFILE</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">true</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> cargo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --bin</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> irohad</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --config</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./config.toml</span></span></code></pre></div><p>Use the same profile consistently across validators in the same network.</p>`,27)])])}const g=i(n,[["render",l]]);export{c as __pageData,g as default};
